import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  Outlet,
  useNavigate
} from "react-router-dom";
import logo from "./assets/logo.png";
import AIAssistant from "./components/aiassistant.js";
import "./App.css";
import { useState, createContext, useContext } from "react";

const AuthContext = createContext();

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(
    JSON.parse(localStorage.getItem("user")) || null
  );

  const login = (data) => {
    localStorage.setItem("user", JSON.stringify(data));
    setUser(data);
  };

  const logout = () => {
    localStorage.removeItem("user");
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

const useAuth = () => useContext(AuthContext);

const ProtectedRoute = ({ role }) => {
  const { user } = useAuth();

  if (!user) return <Navigate to="/login" />;
  if (role && user.role !== role) return <Navigate to="/" />;

  return <Outlet />;
};

const Home = ({ setShowLogin }) => {
  const { user } = useAuth();

  const services = [
    "Cleaning",
    "Plumbing",
    "Electrical",
    "Carpentry",
    "Painting",
    "Gardening",
    "Cooking",
    "Car Wash",
    "Pest Control",
    "Event Planning"
  ];

  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [showDropdown, setShowDropdown] = useState(false);

  const handleSearch = (value) => {
    setQuery(value);

    if (!value.trim()) {
      setResults([]);
      setShowDropdown(false);
      return;
    }

    const filtered = services.filter((service) =>
      service.toLowerCase().includes(value.toLowerCase())
    );

    setResults(filtered);
    setShowDropdown(true);
  };

  return (
    <>
      <nav
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          padding: "1rem"
        }}
        className="navbar"
      >
        <img src={logo} alt="logo" style={{ height: "40px" }} />

        {!user && (
          <button onClick={() => setShowLogin(true)}>
            Login / Register
          </button>
        )}

        {user && user.role === "client" && (
          <button onClick={() => (window.location.href = "/client")}>
            Client Dashboard
          </button>
        )}

        {user && user.role === "tasker" && (
          <button onClick={() => (window.location.href = "/tasker")}>
            Tasker Dashboard
          </button>
        )}

        {user && user.role === "admin" && (
          <button onClick={() => (window.location.href = "/admin")}>
            Admin Dashboard
          </button>
        )}
      </nav>

      <div className="hero">
        <h1>Book trusted help for home tasks</h1>
      </div>

      {/* 🔥 SMART SEARCH */}
      <div className="search">
        <div className="search-inner" style={{ position: "relative" }}>
          <input
            value={query}
            onChange={(e) => handleSearch(e.target.value)}
            onFocus={() => setShowDropdown(true)}
            placeholder="Search services..."
          />

          <button>Search</button>

          {showDropdown && results.length > 0 && (
            <div className="search-dropdown">
              {results.map((item, i) => (
                <div
                  key={i}
                  className="dropdown-item"
                  onClick={() => {
                    setQuery(item);
                    setShowDropdown(false);
                    window.location.href = `/Tasks?category=${item}`;
                  }}
                >
                  🔍 {item}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      <footer
        style={{
          textAlign: "center",
          padding: "1rem",
          marginTop: "2rem",
          color: "#000"
        }}
      >
        © 2024 Taskiva. All rights reserved.
      </footer>
    </>
  );
};

function Login({ setShowLogin }) {
  const { login } = useAuth();
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("client");

  const handleLogin = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/auth/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ email, password })
      });

      const data = await res.json();

      if (res.ok) {
        login({ ...data, email, role });

        if (role === "client") navigate("/client");
        else if (role === "tasker") navigate("/tasker");
        else navigate("/admin");
      } else {
        alert(data.message);
      }
    } catch {
      alert("Error logging in");
    }
  };

  return (
    <>
      <div>
        <h2>Login</h2>
        <button onClick={() => setShowLogin(false)}>
          Back to Home
        </button>

        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <select value={role} onChange={(e) => setRole(e.target.value)}>
          <option value="client">Client</option>
          <option value="tasker">Tasker</option>
          <option value="admin">Admin</option>
        </select>

        <button onClick={handleLogin}>Login</button>
      </div>

      <footer style={{ textAlign: "center", padding: "1rem" }}>
        © 2024 TaskMaster. All rights reserved.
      </footer>
    </>
  );
}

const Client = () => <h2>Client Dashboard</h2>;
const Tasker = () => <h2>Tasker Dashboard</h2>;
const Admin = () => <h2>Admin Dashboard</h2>;

export default function App() {
  const [showLogin, setShowLogin] = useState(false);

  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route
            path="/"
            element={
              showLogin ? (
                <Login setShowLogin={setShowLogin} />
              ) : (
                <Home setShowLogin={setShowLogin} />
              )
            }
          />

          <Route path="/login" element={<Login setShowLogin={setShowLogin} />} />

          <Route element={<ProtectedRoute role="client" />}>
            <Route path="/client" element={<Client />} />
          </Route>

          <Route element={<ProtectedRoute role="tasker" />}>
            <Route path="/tasker" element={<Tasker />} />
          </Route>

          <Route element={<ProtectedRoute role="admin" />}>
            <Route path="/admin" element={<Admin />} />
          </Route>
        </Routes>

        <AIAssistant />
      </BrowserRouter>
    </AuthProvider>
  );
}
